Onboard LED is on GP25 for the regular Pico (not the Pico W).

```cpp
#include <Arduino.h>

const int LED_PIN = 25;

void setup() {
  pinMode(LED_PIN, OUTPUT);
}

void loop() {
  digitalWrite(LED_PIN, HIGH);
  delay(500);
  digitalWrite(LED_PIN, LOW);
  delay(500);
}
```

USB-Serial-JTAG appears as the default Serial on the S3.

```cpp
#include <Arduino.h>

void setup() {
  Serial.begin(115200);
  while (!Serial && millis() < 2000) { /* wait briefly for USB CDC */ }
  Serial.println("boot");
}

void loop() {
  Serial.println("Hello world");
  delay(1000);
}
```

Button wires from D2 to GND. INPUT_PULLUP makes the line idle HIGH and read LOW when pressed.

```cpp
#include <Arduino.h>

const int BUTTON_PIN = 2;
const int LED_PIN = 13;

void setup() {
  pinMode(BUTTON_PIN, INPUT_PULLUP);
  pinMode(LED_PIN, OUTPUT);
}

void loop() {
  bool pressed = digitalRead(BUTTON_PIN) == LOW;
  digitalWrite(LED_PIN, pressed ? HIGH : LOW);
}
```

R4 ADC is 14-bit, full scale at 3.3 V. Use analogReadResolution(14) explicitly so this code stays correct if a future sketch changes the global resolution.

```cpp
#include <Arduino.h>

const int POT_PIN = A0;
const float VREF_MV = 3300.0f;
const int ADC_MAX = 16383;  // 14-bit

void setup() {
  Serial.begin(115200);
  analogReadResolution(14);
}

void loop() {
  int raw = analogRead(POT_PIN);
  float mv = (raw * VREF_MV) / ADC_MAX;
  Serial.printf("raw=%d  mv=%.1f\n", raw, mv);
  delay(100);
}
```

On the ESP32 Arduino core (3.x), `analogWrite()` is implemented via the LEDC peripheral. Default 8-bit resolution at 1 kHz works for an LED.

```cpp
#include <Arduino.h>
#include <math.h>

const int LED_PIN = 5;
const float PERIOD_MS = 4000.0f;

void setup() {
  pinMode(LED_PIN, OUTPUT);
}

void loop() {
  float t = (millis() % (uint32_t)PERIOD_MS) / PERIOD_MS;  // 0..1
  float s = (sinf(t * 2.0f * PI) + 1.0f) * 0.5f;            // 0..1
  analogWrite(LED_PIN, (int)(s * 255));
  delay(10);
}
```

Use millis() comparison to keep loop() cooperative.

```cpp
#include <Arduino.h>

const uint32_t INTERVAL_MS = 250;
uint32_t lastTick = 0;
uint32_t counter = 0;

void setup() {
  Serial.begin(115200);
}

void loop() {
  uint32_t now = millis();
  if (now - lastTick >= INTERVAL_MS) {
    lastTick = now;
    Serial.println(counter++);
  }
  // other non-blocking work goes here
}
```

Mark the toggle flag volatile so the ISR-to-loop hand-off is correct.

```cpp
#include <Arduino.h>

const int IRQ_PIN = 2;
const int LED_PIN = 13;

volatile bool toggleRequested = false;

void onEdge() { toggleRequested = true; }

void setup() {
  pinMode(LED_PIN, OUTPUT);
  pinMode(IRQ_PIN, INPUT_PULLUP);
  attachInterrupt(digitalPinToInterrupt(IRQ_PIN), onEdge, FALLING);
}

void loop() {
  if (toggleRequested) {
    toggleRequested = false;
    digitalWrite(LED_PIN, !digitalRead(LED_PIN));
  }
}
```

```cpp
#include <Arduino.h>

String line;

void setup() {
  Serial.begin(115200);
}

void loop() {
  while (Serial.available()) {
    char c = (char)Serial.read();
    if (c == '\n' || c == '\r') {
      if (line.length()) {
        line.toUpperCase();
        Serial.println(line);
        line = "";
      }
    } else {
      line += c;
    }
  }
}
```

The NeoPixel needs power gate GPIO21 high before it will respond. Adafruit_NeoPixel covers the WS2812 protocol cleanly.

```cpp
#include <Arduino.h>
#include <Adafruit_NeoPixel.h>

const int NEOPIXEL_PIN = 33;
const int NEOPIXEL_PWR = 21;

Adafruit_NeoPixel pixel(1, NEOPIXEL_PIN, NEO_GRB + NEO_KHZ800);

void setup() {
  pinMode(NEOPIXEL_PWR, OUTPUT);
  digitalWrite(NEOPIXEL_PWR, HIGH);
  pixel.begin();
  pixel.setBrightness(40);
  pixel.setPixelColor(0, pixel.Color(0, 0, 255));
  pixel.show();
}

void loop() {}
```

The earlephilhower core implements tone() via PWM on RP2040.

```cpp
#include <Arduino.h>

const int OUT_PIN = 14;
const int FREQ_HZ = 1000;

void setup() {
  pinMode(OUT_PIN, OUTPUT);
  tone(OUT_PIN, FREQ_HZ);  // continuous until noTone()
}

void loop() {}
```
